FIXTURES.BadgeMapper = (function() {

  var NO_IMAGE = '_no-image.gif';

  function getBadgeForTeam(teamName) {
    var badgeFileName = badgeTeamMap[teamName];
    if (!badgeFileName) {
      badgeFileName = NO_IMAGE;
    }
    return badgeFileName;
  }

  var badgeTeamMap = {
    'Arsenal': 'arsenal.svg',
    'Bournemouth': 'bournemouth.svg',
    'Burnley': 'burnley.svg',
    'Chelsea': 'chelsea.svg',
    'Crystal Palace': 'crystal_palace.svg',
    'Everton': 'everton.svg',
    'Hull City': 'hull_city.svg',
    'Leicester City': 'leicester.svg',
    'Liverpool': 'liverpool.svg',
    'Manchester City': 'manchester_city.svg',
    'Middlesbrough': 'middlesbrough.svg',
    'Norwich': 'norwich.svg',
    'Southampton': 'southampton.svg',
    'Sunderland': 'sunderland.svg',
    'Stoke City': 'stoke_city.svg',
    'Swansea City': 'swansea.svg',
    'Tottenham Hotspur': 'tottenham.svg',
    'Watford': 'watford.svg',
    'West Bromwich Albion': 'wba.svg',
    'West Ham United': 'west_ham_united.svg'
  }

  return {
    getBadgeForTeam: getBadgeForTeam
  }

}());
