'use strict';

var FIXTURES = FIXTURES || {};

window.onload = function() {

  var cardContainer = document.querySelector('.fixture-cards-container');

  FIXTURES.FixturesLoader.load().then(function(fixtures) {
    for (var i = 0; i < fixtures.length; i += 1) {
      var card = FIXTURES.Card.createFixtureCard(fixtures[i]);
      cardContainer.appendChild(card);
      console.log(fixtures[i]);
    }
  })
}
